local _M = {}

-- XML parser implementation for OpenResty
-- Handles SOAP API gateway XML parsing with entity reference support

local ngx = ngx
local string_find = string.find
local string_sub = string.sub
local string_gsub = string.gsub
local string_match = string.match
local table_insert = table.insert

-- Built-in entity references
local entity_map = {
    ["&amp;"]  = "&",
    ["&lt;"]   = "<",
    ["&gt;"]   = ">",
    ["&quot;"] = '"',
    ["&apos;"] = "'",
}

-- Resolve standard XML entity references and numeric character references
local function resolve_entities(text)
    if not text then
        return text
    end
    -- Resolve named entities
    text = string_gsub(text, "&%w+;", function(entity)
        return entity_map[entity] or entity
    end)
    -- Resolve decimal numeric character references &#NNN;
    text = string_gsub(text, "&#(%d+);", function(code)
        return string.char(tonumber(code))
    end)
    -- Resolve hex numeric character references &#xHHH;
    text = string_gsub(text, "&#x(%x+);", function(code)
        return string.char(tonumber(code, 16))
    end)
    return text
end

-- Trim whitespace
local function trim(s)
    if not s then return nil end
    return string_match(s, "^%s*(.-)%s*$")
end

-- Simple XML parser that returns a nested table structure
-- Each node: { tag = "name", attr = {}, ns = "namespace_prefix", children = {}, text = "" }
local function parse_xml(xml_string)
    if not xml_string or xml_string == "" then
        return nil, "empty XML input"
    end

    -- Remove XML declaration if present
    xml_string = string_gsub(xml_string, "<%?xml[^%?]*%?>", "")

    -- Remove comments
    xml_string = string_gsub(xml_string, "<!%-%-.-%--%>", "")

    -- Remove CDATA sections but keep content
    xml_string = string_gsub(xml_string, "<!%[CDATA%[(.-)%]%]>", "%1")

    local stack = {}
    local root = { children = {} }
    local current = root
    local pos = 1

    while pos <= #xml_string do
        -- Find next tag
        local tag_start = string_find(xml_string, "<", pos)
        if not tag_start then
            -- Remaining text
            local remaining = trim(string_sub(xml_string, pos))
            if remaining and remaining ~= "" then
                current.text = (current.text or "") .. resolve_entities(remaining)
            end
            break
        end

        -- Capture text before this tag
        if tag_start > pos then
            local text_content = string_sub(xml_string, pos, tag_start - 1)
            text_content = trim(text_content)
            if text_content and text_content ~= "" then
                current.text = (current.text or "") .. resolve_entities(text_content)
            end
        end

        local tag_end = string_find(xml_string, ">", tag_start)
        if not tag_end then
            return nil, "malformed XML: unclosed tag at position " .. tag_start
        end

        local tag_content = string_sub(xml_string, tag_start + 1, tag_end - 1)

        if string_sub(tag_content, 1, 1) == "/" then
            -- Closing tag
            local closing_tag = trim(string_sub(tag_content, 2))
            if current.tag then
                local full_tag = current.tag
                if current.ns then
                    full_tag = current.ns .. ":" .. current.tag
                end
                if closing_tag ~= full_tag and closing_tag ~= current.tag then
                    return nil, "mismatched closing tag: expected </" .. (full_tag) .. "> but got </" .. closing_tag .. ">"
                end
            end
            current = table.remove(stack)
            if not current then
                return nil, "malformed XML: extra closing tag </" .. tag_content .. ">"
            end
        elseif string_sub(tag_content, 1, 1) == "!" then
            -- Skip processing instructions, doctypes etc.
        else
            -- Opening tag (possibly self-closing)
            local self_closing = false
            if string_sub(tag_content, -1) == "/" then
                self_closing = true
                tag_content = string_sub(tag_content, 1, -2)
            end

            -- Parse tag name and attributes
            local tag_name = string_match(tag_content, "^(%S+)")
            if not tag_name then
                return nil, "malformed XML: empty tag at position " .. tag_start
            end

            local node = {
                tag = tag_name,
                attr = {},
                children = {},
                text = "",
                ns = nil,
                ns_map = {},
            }

            -- Extract namespace prefix
            local ns_prefix, local_name = string_match(tag_name, "^(%w+):(.+)$")
            if ns_prefix then
                node.ns = ns_prefix
                node.tag = local_name
            end

            -- Parse attributes
            local attr_string = string_sub(tag_content, #tag_name + 1)
            for attr_name, attr_value in string.gmatch(attr_string, '(%S+)%s*=%s*"([^"]*)"') do
                node.attr[attr_name] = resolve_entities(attr_value)
                -- Track namespace declarations
                local ns_decl = string_match(attr_name, "^xmlns:(%w+)$")
                if ns_decl then
                    node.ns_map[ns_decl] = resolve_entities(attr_value)
                elseif attr_name == "xmlns" then
                    node.ns_map[""] = resolve_entities(attr_value)
                end
            end
            -- Also handle single-quoted attributes
            for attr_name, attr_value in string.gmatch(attr_string, "(%S+)%s*=%s*'([^']*)'") do
                if not node.attr[attr_name] then
                    node.attr[attr_name] = resolve_entities(attr_value)
                    local ns_decl = string_match(attr_name, "^xmlns:(%w+)$")
                    if ns_decl then
                        node.ns_map[ns_decl] = resolve_entities(attr_value)
                    elseif attr_name == "xmlns" then
                        node.ns_map[""] = resolve_entities(attr_value)
                    end
                end
            end

            table_insert(current.children, node)

            if not self_closing then
                table_insert(stack, current)
                current = node
            end
        end

        pos = tag_end + 1
    end

    if #stack > 0 then
        return nil, "malformed XML: unclosed tags remain"
    end

    if #root.children == 0 then
        return nil, "no root element found"
    end

    return root.children[1], nil
end

-- Helper: find a child element by tag name (ignoring namespace prefix)
local function find_child(node, tag_name)
    if not node or not node.children then
        return nil
    end
    for _, child in ipairs(node.children) do
        if child.tag == tag_name then
            return child
        end
    end
    return nil
end

-- Helper: find all children with a given tag name
local function find_children(node, tag_name)
    local results = {}
    if not node or not node.children then
        return results
    end
    for _, child in ipairs(node.children) do
        if child.tag == tag_name then
            table_insert(results, child)
        end
    end
    return results
end

-- Helper: recursively find element by tag name (depth-first)
local function find_element(node, tag_name)
    if not node then return nil end
    if node.tag == tag_name then
        return node
    end
    if node.children then
        for _, child in ipairs(node.children) do
            local found = find_element(child, tag_name)
            if found then
                return found
            end
        end
    end
    return nil
end

-- Helper: get text content of a node (including nested text)
local function get_text(node)
    if not node then return nil end
    if node.text and node.text ~= "" then
        return node.text
    end
    -- Concatenate text from children if no direct text
    local parts = {}
    if node.children then
        for _, child in ipairs(node.children) do
            local t = get_text(child)
            if t then
                table_insert(parts, t)
            end
        end
    end
    if #parts > 0 then
        return table.concat(parts, "")
    end
    return nil
end

-- Extract SOAP envelope components
local function parse_soap_envelope(root)
    if not root then
        return nil, "no root element"
    end

    local result = {
        soap_version = nil,
        header = nil,
        body = nil,
        action = nil,
        method = nil,
        params = {},
    }

    -- Detect SOAP version from namespace
    local envelope_tag = root.tag
    if envelope_tag ~= "Envelope" then
        return nil, "root element is not a SOAP Envelope, got: " .. tostring(envelope_tag)
    end

    -- Check SOAP namespace
    if root.ns then
        local ns_uri = root.attr["xmlns:" .. root.ns] or (root.ns_map and root.ns_map[root.ns])
        if ns_uri then
            if string_find(ns_uri, "soap/envelope") or string_find(ns_uri, "soap%-envelope") then
                result.soap_version = "1.1"
            elseif string_find(ns_uri, "soap%-envelope") or string_find(ns_uri, "2003/05/soap%-envelope") then
                result.soap_version = "1.2"
            end
        end
    end

    if not result.soap_version then
        -- Default guess
        result.soap_version = "1.1"
    end

    -- Find Header and Body
    local header_node = find_child(root, "Header")
    local body_node = find_child(root, "Body")

    if not body_node then
        return nil, "SOAP Body not found in envelope"
    end

    result.header = header_node
    result.body = body_node

    -- Extract SOAPAction from header if present
    if header_node then
        local action_node = find_element(header_node, "Action")
        if action_node then
            result.action = get_text(action_node)
        end
    end

    -- Extract method name (first child of Body)
    if body_node.children and #body_node.children > 0 then
        local method_node = body_node.children[1]
        result.method = method_node.tag
        result.method_ns = method_node.ns

        -- Extract parameters from method node children
        if method_node.children then
            for _, param_node in ipairs(method_node.children) do
                local param_name = param_node.tag
                local param_value = get_text(param_node)

                -- If the param has children, treat it as a complex type
                if param_node.children and #param_node.children > 0 and not param_value then
                    local complex_value = {}
                    for _, sub_node in ipairs(param_node.children) do
                        complex_value[sub_node.tag] = get_text(sub_node)
                    end
                    result.params[param_name] = complex_value
                else
                    result.params[param_name] = param_value
                end
            end
        end
    end

    return result, nil
end

-- Extract SOAP headers as key-value pairs
local function extract_soap_headers(header_node)
    local headers = {}
    if not header_node or not header_node.children then
        return headers
    end
    for _, child in ipairs(header_node.children) do
        local key = child.tag
        local value = get_text(child)
        if value then
            headers[key] = value
        else
            -- Nested header element
            local nested = {}
            if child.children then
                for _, sub in ipairs(child.children) do
                    nested[sub.tag] = get_text(sub)
                end
            end
            headers[key] = nested
        end
    end
    return headers
end

-- Main request handler for OpenResty
function _M.handle_request()
    -- Read request body
    ngx.req.read_body()
    local body = ngx.req.get_body_data()

    if not body then
        -- Body might be in a temp file
        local file_name = ngx.req.get_body_file()
        if file_name then
            local f = io.open(file_name, "r")
            if f then
                body = f:read("*a")
                f:close()
            end
        end
    end

    if not body or body == "" then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>soap:Client</faultcode>
      <faultstring>Empty request body</faultstring>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>]])
        return ngx.exit(400)
    end

    -- Parse the XML
    local xml_root, parse_err = parse_xml(body)
    if not xml_root then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>soap:Client</faultcode>
      <faultstring>XML Parse Error: %s</faultstring>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>]], parse_err))
        return ngx.exit(400)
    end

    -- Parse SOAP envelope structure
    local soap_data, soap_err = parse_soap_envelope(xml_root)
    if not soap_data then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>soap:Client</faultcode>
      <faultstring>SOAP Parse Error: %s</faultstring>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>]], soap_err))
        return ngx.exit(400)
    end

    -- Also check SOAPAction HTTP header
    local soap_action_header = ngx.req.get_headers()["SOAPAction"]
    if soap_action_header then
        -- Remove surrounding quotes if present
        soap_action_header = string_gsub(soap_action_header, '^"(.*)"$', "%1")
        if not soap_data.action then
            soap_data.action = soap_action_header
        end
    end

    -- Extract headers
    local soap_headers = extract_soap_headers(soap_data.header)

    -- Log parsed request info
    ngx.log(ngx.INFO, string.format(
        "SOAP Request - Version: %s, Action: %s, Method: %s",
        soap_data.soap_version or "unknown",
        soap_data.action or "none",
        soap_data.method or "unknown"
    ))

    -- Store parsed data in ngx.ctx for downstream processing
    ngx.ctx.soap_data = soap_data
    ngx.ctx.soap_headers = soap_headers
    ngx.ctx.soap_method = soap_data.method
    ngx.ctx.soap_params = soap_data.params
    ngx.ctx.soap_action = soap_data.action
    ngx.ctx.soap_version = soap_data.soap_version

    return soap_data
end

-- Generate a SOAP fault response
function _M.send_fault(fault_code, fault_string, detail, http_status)
    http_status = http_status or 500
    local detail_xml = ""
    if detail then
        detail_xml = string.format("<detail>%s</detail>", detail)
    end

    ngx.status = http_status
    ngx.header["Content-Type"] = "text/xml; charset=utf-8"
    ngx.say(string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>%s</faultcode>
      <faultstring>%s</faultstring>
      %s
    </soap:Fault>
  </soap:Body>
</soap:Envelope>]], fault_code, fault_string, detail_xml))
    return ngx.exit(http_status)
end

-- Generate a SOAP success response wrapping arbitrary XML content
function _M.send_response(method_name, response_xml, soap_version)
    soap_version = soap_version or "1.1"
    local ns_uri
    if soap_version == "1.2" then
        ns_uri = "http://www.w3.org/2003/05/soap-envelope"
    else
        ns_uri = "http://schemas.xmlsoap.org/soap/envelope/"
    end

    ngx.status = 200
    ngx.header["Content-Type"] = "text/xml; charset=utf-8"
    ngx.say(string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="%s">
  <soap:Body>
    <%sResponse>
      %s
    </%sResponse>
  </soap:Body>
</soap:Envelope>]], ns_uri, method_name, response_xml, method_name))
    return ngx.exit(200)
end

-- Route SOAP requests to handlers based on method name
function _M.route(handlers)
    local soap_data = _M.handle_request()
    if not soap_data then
        return -- Error already sent
    end

    local method = soap_data.method
    if not method then
        return _M.send_fault("soap:Client", "No method specified in SOAP body", nil, 400)
    end

    local handler = handlers[method]
    if not handler then
        return _M.send_fault(
            "soap:Client",
            string.format("Unknown method: %s", method),
            nil,
            404
        )
    end

    -- Call the handler with parsed params and full soap data
    local ok, err = pcall(handler, soap_data.params, soap_data)
    if not ok then
        ngx.log(ngx.ERR, "SOAP handler error for method " .. method .. ": " .. tostring(err))
        return _M.send_fault(
            "soap:Server",
            "Internal server error",
            tostring(err),
            500
        )
    end
end

