_M.parse_xml = parse_xml
_M.parse_soap_envelope = parse_soap_envelope
_M.find_child = find_child
_M.find_children = find_children
_M.find_element = find_element
_M.get_text = get_text
_M.resolve_entities = resolve_entities
_M.extract_soap_headers = extract_soap_headers

return _M